import{_ as t,c as a,o as r,ah as s}from"./chunks/framework.C-x9UAyH.js";const b=JSON.parse('{"title":"Beneficios y características de las pruebas en Springboot","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"springboot/pruebas_unitarias/benef_caract.md","filePath":"springboot/pruebas_unitarias/benef_caract.md","lastUpdated":1760485751000}'),o={name:"springboot/pruebas_unitarias/benef_caract.md"};function n(i,e,d,c,l,u){return r(),a("div",null,[...e[0]||(e[0]=[s('<h1 id="beneficios-y-caracteristicas-de-las-pruebas-en-springboot" tabindex="-1">Beneficios y características de las pruebas en Springboot <a class="header-anchor" href="#beneficios-y-caracteristicas-de-las-pruebas-en-springboot" aria-label="Permalink to &quot;Beneficios y características de las pruebas en Springboot&quot;">​</a></h1><p>Las pruebas unitarias son una práctica de programación que implica verificar cada unidad individual de código para asegurar que funciona correctamente. Una unidad puede ser un método, una clase o incluso un módulo.</p><h2 id="beneficios-de-las-pruebas" tabindex="-1">Beneficios de las pruebas <a class="header-anchor" href="#beneficios-de-las-pruebas" aria-label="Permalink to &quot;Beneficios de las pruebas&quot;">​</a></h2><ul><li>Detección temprana de errores</li><li>Facilitan el mantenimiento del código</li><li>Sirven como documentación adicional</li></ul><h2 id="caracteristicas-de-junit" tabindex="-1">Características de JUnit <a class="header-anchor" href="#caracteristicas-de-junit" aria-label="Permalink to &quot;Características de JUnit&quot;">​</a></h2><p>JUnit es el <strong>marco de pruebas más utilizado en Java</strong>, diseñado para facilitar la creación, organización y ejecución de pruebas unitarias.</p><p>Está compuesto por <strong>tres módulos principales</strong>:</p><table tabindex="0"><thead><tr><th>🧩 Módulo</th><th>💡 Descripción</th></tr></thead><tbody><tr><td><strong>JUnit Platform</strong></td><td>Define la base sobre la cual se ejecutan las pruebas y los motores de test.</td></tr><tr><td><strong>JUnit Jupiter</strong></td><td>Proporciona la nueva API y las anotaciones modernas de JUnit 5.</td></tr><tr><td><strong>JUnit Vintage</strong></td><td>Permite ejecutar pruebas escritas en versiones anteriores (JUnit 3 y 4).</td></tr></tbody></table><hr><div class="info custom-block"><p class="custom-block-title">🧭 <strong>Anotaciones principales en JUnit</strong></p><p>Las anotaciones permiten controlar el ciclo de vida de las pruebas.</p></div><table tabindex="0"><thead><tr><th>🏷️ Anotación</th><th>📝 Descripción</th></tr></thead><tbody><tr><td><strong><code>@Test</code></strong></td><td>Indica que el método es una prueba unitaria.</td></tr><tr><td><strong><code>@BeforeEach</code> / <code>@AfterEach</code></strong></td><td>Se ejecutan antes y después de <strong>cada</strong> prueba.</td></tr><tr><td><strong><code>@BeforeAll</code> / <code>@AfterAll</code></strong></td><td>Se ejecutan una sola vez, antes y después de <strong>todas</strong> las pruebas de la clase.</td></tr><tr><td><strong><code>@DisplayName</code></strong></td><td>Permite asignar un nombre descriptivo y legible a la prueba.</td></tr></tbody></table><hr><div class="tip custom-block"><p class="custom-block-title">✅ <strong>Assertions más comunes</strong></p><p>Las <em>assertions</em> permiten verificar los resultados esperados durante la ejecución de las pruebas.</p></div><table tabindex="0"><thead><tr><th>🧪 Assertion</th><th>🧠 Propósito</th></tr></thead><tbody><tr><td><strong><code>assertEquals(a, b)</code></strong></td><td>Verifica que dos valores sean iguales.</td></tr><tr><td><strong><code>assertTrue(condición)</code> / <code>assertFalse(condición)</code></strong></td><td>Comprueba si una condición es verdadera o falsa.</td></tr><tr><td><strong><code>assertNull(obj)</code> / <code>assertNotNull(obj)</code></strong></td><td>Verifica si un objeto es nulo o no nulo.</td></tr><tr><td><strong><code>assertThrows(Exception.class, ...)</code></strong></td><td>Comprueba que se lance una excepción específica.</td></tr></tbody></table><hr><p>📘 <em>En conjunto, JUnit permite escribir pruebas más legibles, organizadas y confiables para asegurar la calidad del código en proyectos Java.</em></p>',16)])])}const g=t(o,[["render",n]]);export{b as __pageData,g as default};
